import { JobUsers } from "src/app/views/Models/Users/JobUsers";
import { User } from "./../../../Models/Permissions/User";
import { LoanApp } from "src/app/views/Models/Loan/LoanApp";
import { HttpClient, HttpHeaders } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { AlertController } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { TranslateService } from "@ngx-translate/core";
import { Job } from "src/app/views/Models/Users/Job";
import { isThisQuarter } from "date-fns";
import { ActivatedRoute, Params } from "@angular/router";
import { pagingService } from "src/app/core/services/paging.service";
import { JobsService } from "src/app/core/services/jobs.service";
import { Tree } from "src/app/views/Models/Users/Tree";

@Component({
  selector: "app-job-supervision",
  templateUrl: "./job-supervision.page.html",
  styleUrls: ["./job-supervision.page.scss"],
})
export class JobSupervisionPage implements OnInit {
  showLoader: boolean = false;
  currentLanguage: string = localStorage.getItem("currentLanguage") || "en-GB";
  textDir: string = "ltr";
  params: Params = {};

  jobHierarchy: Tree<Job>[];
  jobs: Job[];
  selectedJob: Job;
  initialLoad: boolean = true;

  pageSize: number;
  page = 1;
  resultsCount;

  jobsPageNo = 1;
  jobsResultCount;

  isSearching: boolean = true;
  selectedUser: User;

  loanApps: LoanApp[];
  selectedLoanApp: LoanApp;

  jobUsers: JobUsers[];
  selectedJobUser: JobUsers;

  isModalOpen = false;

  constructor(
    private http: HttpClient,
    private activatedRoute: ActivatedRoute,
    private env: EnvService,
    private alertServices: AlertService,
    public translate: TranslateService,
    public pagingService: pagingService,
    private jobsService: JobsService
  ) {}

  async ngOnInit() {
    this.showLoader = true;
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
    this.params = this.activatedRoute.snapshot.queryParams;
    this.initialLoad =
      this.params["jobId"] &&
      this.params["applicationKey"] &&
      this.params["username"];
    this.translate.get(`languages.${this.currentLanguage}.dir`).subscribe({
      next: (dir) => {
        this.textDir = dir;
        console.log(dir);
      },
      error: () => {
        this.textDir = "ltr";
      },
    });

    this.jobHierarchy = await this.jobsService.getJobsSupervisedTree();
    if (this.params["jobId"] && this.initialLoad) {
      this.jobs = await this.jobsService.getJobsSupervised();
      this.selectedJob = this.jobs.find(
        (x) => x.job_id == this.params["jobId"]
      );
    }
    console.log(this.jobHierarchy);
    this.showLoader = false;
  }

  loadJobUserLoanApps(user: User) {
    this.showLoader = true;
    const httpOptions = {
      headers: new HttpHeaders({
        "Content-Type": "application/json",
      }),
    };
    this.http
      .post<LoanApp[]>(
        this.env.API_URL +
          `api/Job/GetLoanAppsAssignedToJobUserPaged?page=${this.page}&pageSize=${this.pageSize}&username=${user.user_name}`,
        this.selectedJob.job_id,
        httpOptions
      )
      .subscribe({
        next: (data) => {
          this.loanApps = data["result"];
          this.resultsCount = data["totalCount"];
          if (this.params["applicationKey"] && this.initialLoad)
            this.reassignLoanApp(
              this.loanApps.filter(
                (x) => x.application_key == this.params["applicationKey"]
              )[0]
            );
          console.log(this.loanApps);
        },
        error: (err) => {
          console.log(err);
        },
      });
    this.http
      .get<JobUsers[]>(
        this.env.API_URL +
          `api/Job/GetJobUsersBySupervisor?job=${this.selectedJob.job_id}&branch=${this.selectedUser.branch_code}`,
        httpOptions
      )
      .subscribe({
        next: (data) => {
          this.jobUsers = data.filter(
            (x) => x.user_name != this.selectedUser.user_name
          );
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  loadActiveJobUsers(job: Job) {
    this.selectedJob = job;
    this.isSearching = true;
  }

  userSelected(event: User): void {
    this.selectedUser = event;
    this.loadJobUserLoanApps(event);
    this.isSearching = false;
  }

  reassignLoanApp(loanApp: LoanApp) {
    this.selectedLoanApp = loanApp;
    this.setOpen(true);
  }

  deselectJob() {
    this.selectedJob = null;
    this.selectedUser = null;
    this.isSearching = true;
    this.initialLoad = false;
  }

  deselectUser() {
    this.isSearching = true;
    this.selectedUser = null;
    this.initialLoad = false;
  }

  changePage(newPage: number): void {
    this.page = newPage;
    this.loadJobUserLoanApps(this.selectedUser);
  }

  changeJobsPage(newPage: number): void {
    this.jobsPageNo = newPage;
  }

  setOpen(isOpen: boolean) {
    this.isModalOpen = isOpen;
    this.initialLoad = false;
  }

  onChange($event: Event) {
    this.selectedJobUser = this.jobUsers.filter(
      (x) => x.user_name == $event["detail"].value
    )[0];
  }

  saveChanges() {
    const body = {
      user_name: this.selectedUser.user_name,
      branch_code: this.selectedUser.branch_code.toString(),
      job_id: this.selectedJob.job_id,
      user_assigned: this.selectedJobUser.user_name,
      doc_key: this.selectedLoanApp.application_key,
    };
    console.log(body);
    const httpOptions = {
      headers: new HttpHeaders({
        "Content-Type": "application/json",
      }),
    };
    this.http
      .post<LoanApp[]>(
        this.env.API_URL + `api/Job/ReassignWork`,
        body,
        httpOptions
      )
      .subscribe({
        next: async () => {
          await this.loadJobUserLoanApps(this.selectedUser);
          this.initialLoad = false;
          this.setOpen(false);
        },
        error: (err) => {
          console.log(err);
          this.initialLoad = false;
          this.setOpen(false);
        },
      });
  }
}
